#define fp float

#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

__kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    int global_id = get_global_id(0);

    int box_idx = global_id / NUMBER_THREADS;
    int particle_idx = global_id % NUMBER_THREADS;

    if (box_idx >= dim.number_boxes || particle_idx >= NUMBER_PAR_PER_BOX)
        return;

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[box_idx].offset + particle_idx;
    FOUR_VECTOR rA = rv[first_i];
    FOUR_VECTOR fA = fv[first_i];

    for (int k = 0; k <= box[box_idx].nn; k++) {
        int pointer;
        if (k == 0) {
            pointer = box_idx;
        } else {
            pointer = box[box_idx].nei[k-1].number;
        }

        long first_j = box[pointer].offset;

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            long idx_j = first_j + j;
            FOUR_VECTOR rB = rv[idx_j];
            fp qB = qv[idx_j];

            fp r2 = rA.v + rB.v - DOT(rA, rB);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;

            THREE_VECTOR d;
            d.x = rA.x - rB.x;
            d.y = rA.y - rB.y;
            d.z = rA.z - rB.z;

            fp fxij = fs * d.x;
            fp fyij = fs * d.y;
            fp fzij = fs * d.z;

            fA.v += qB * vij;
            fA.x += qB * fxij;
            fA.y += qB * fyij;
            fA.z += qB * fzij;
        }
    }

    fv[first_i] = fA;
}
